module decoder_3to8(IN, EN, input_data);
input [2:0] IN;
input EN;
output reg [7:0] input_data;

always@(*) begin
    if(EN)
        case(IN)
            3'b000: input_data = 8'b00000001;
            3'b001: input_data = 8'b00000010;
            3'b010: input_data = 8'b00000100;
            3'b011: input_data = 8'b00001000;
            3'b100: input_data = 8'b00010000;
            3'b101: input_data = 8'b00100000;
            3'b110: input_data = 8'b01000000;
            3'b111: input_data = 8'b10000000;
            default: input_data = 8'b00000000;
        endcase
    else
        input_data = 8'b00000000;
end

endmodule
